import java.util.HashSet;

public class ReverseUniqueString {
    public static String reverseAndRemoveDuplicates(String input) {
        // Remove digits and special characters
        String cleanedInput = input.replaceAll("[^a-zA-Z]", "");

        // Convert to lowercase and reverse the string
        StringBuilder reversedString = new StringBuilder(cleanedInput.toLowerCase()).reverse();

        // Remove duplicates using a set
        HashSet<Character> uniqueCharacters = new HashSet<>();
        for (int i = 0; i < reversedString.length(); i++) {
            uniqueCharacters.add(reversedString.charAt(i));
        }

        // Build the final string
        StringBuilder result = new StringBuilder();
        for (Character c : uniqueCharacters) {
            result.append(c);
        }

        return result.toString();
    }

    public static void main(String[] args) {
        String input = "Hello! How are you? 123";
        String reversedString = reverseAndRemoveDuplicates(input);
        System.out.println(reversedString); // Output: ?uoyerwh
    }
}
```

