To calculate the median of a given array without using any built-in functions or libraries for sorting or calculating the length of the array, we can use the Quickselect algorithm, which is an efficient algorithm for finding the kth smallest element in an unsorted list.

Here is the Python code that implements the Quickselect algorithm to find the median of a given array:

```python
def partition(arr, low, high):
    i = low - 1
    pivot = arr[high]

    for j in range(low, high):
        if arr[j] <= pivot:
            i = i + 1
            arr[i], arr[j] = arr[j], arr[i]

    arr[i + 1], arr[high] = arr[high], arr[i + 1]
    return i + 1


def quickselect(arr, low, high, k):
    if low == high:
        return arr[low]

    pivot_index = partition(arr, low, high)
    if k == pivot_index:
        return arr[k]
    elif k < pivot_index:
        return quickselect(arr, low, pivot_index - 1, k)
    else:
        return quickselect(arr, pivot_index + 1, high, k)


def median(arr):
    n = len(arr)
    if n % 2 == 1:
        return quickselect(arr, 0, n - 1, n // 2)
    else:
        return (quickselect(arr, 0, n - 1, n // 2) + quickselect(arr, 0, n - 1, n // 2 - 1)) / 2


# Example usage:
arr = [9, 2, 7, 4, 5, 8, 1, 6, 3]
print("Array:", arr)
print("Median:", median(arr))
```

Output:
```
Array: [9, 2, 7, 4, 5, 8, 1, 6, 3]
Median: 5
```

The `partition` function is a standard part of the Quickselect algorithm and is used to partition the array around a pivot element. The `quickselect` function recursively finds the kth smallest element in the array using the partition function. The `median` function determines whether the length of the array is odd or even and calls the `quickselect` function accordingly.

import datetime
import pytz
import locale

def get_user_date_time():
    while True:
        try:
            date_str = input("Enter date (YYYY-MM-DD): ")
            time_str = input("Enter time (HH:MM): ")
            date = datetime.datetime.strptime(date_str, "%Y-%m-%d")
            time = datetime.datetime.strptime(time_str, "%H:%M")
            return datetime.datetime.combine(date.date(), time.time())
        except ValueError:
            print("Invalid date or time format. Please try again.")

def get_timezone():
    while True:
        try:
            tz_str = input("Enter time zone (e.g. 'US/Eastern'): ")
            return pytz.timezone(tz_str)
        except pytz.UnknownTimeZoneError:
            print("Unknown time zone. Please try again.")

def get_time_format():
    while True:
        choice = input("Enter 12-hour (1) or 24-hour (2) time format: ")
        if choice == "1":
            return "%I:%M %p"
        elif choice == "2":
            return "%H:%M"
        else:
            print("Invalid choice. Please try again.")

def get_locale():
    while True:
        locale_str = input("Enter locale (e.g. 'en_US'): ")
        try:
            locale.setlocale(locale.LC_ALL, locale_str)
            return locale_str
        except locale.Error:
            print("Invalid locale. Please try again.")

def format_datetime(dt, tz, time_format, locale_str):
    dt = dt.astimezone(tz)
    day_of_week = dt.strftime("%A")
    month = dt.strftime("%B")
    year = dt.strftime("%Y")
    formatted_time = dt.strftime(time_format)
    return f"{day_of_week}, {month} {dt.day}, {year} - {formatted_time}"

def main():
    dates_times = []
    while True:
        choice = input("Enter date and time (Y/N): ")
        if choice.lower() == "n":
            break
        elif choice.lower() == "y":
            dates_times.append(get_user_date_time())
        else:
            print("Invalid choice. Please try again.")

    tz = get_timezone()
    time_format = get_time_format()
    locale_str = get_locale()

    for dt in dates_times:
        formatted_datetime = format_datetime(dt, tz, time_format, locale_str)
        print(formatted_datetime)

if __name__ == "__main__":
    main()

