class Program
{
    static void Main(string[] args)
    {
        int firstPrime = 0;
        int secondPrime = 0;
        int difference = 0;

        // Start iterating from the first prime number
        for (int i = 2; ; i++)
        {
            if (IsPrime(i))
            {
                // Check if the difference between the current prime and the previous prime is divisible by 7
                if (difference % 7 == 0)
                {
