        String str2 = "abcde";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // true

        str1 = "abc";
        str2 = "def";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // false

        str1 = "abc";
        str2 = "aabbcc";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // true

