from collections import deque

def remove_consecutive_duplicates(mylist):
    if not mylist:
        return [], []

    deduped_list = deque()
    counts = deque()

    prev_num = None
    count = 0

    for num in mylist:
        if num != prev_num:
            if prev_num is not None:
                deduped_list.append(prev_num)
                counts.append(count)
            prev_num = num
            count = 1
        else:
            count += 1

    deduped_list.append(prev_num)
    counts.append(count)

    return list(deduped_list), list(counts)

