#include <iostream>
#include <vector>

std::vector<int> maxSubarraySum(const std::vector<int>& arr) {
    int n = arr.size();
    int maxSum = INT_MIN, currSum = 0;
    int start = 0, end = -1;

    for (int i = 0, j = 0; j < n; j++) {
        currSum += arr[j];

        if (currSum > maxSum) {
            maxSum = currSum;
            start = i;
            end = j;
        }

        if (currSum < 0) {
            currSum = 0;
            i = j + 1;
