def caffeine_impact(age, genetics, medical_condition):
    if age < 30:
        age_factor = 0.5
    elif age < 50:
        age_factor = 1
    else:
        age_factor = 1.5

    if genetics == "High":
        genetics_factor = 2
    elif genetics == "Low":
        genetics_factor = 0.5
